import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub

# Set up service account with broad permissions
os.environ["GOOGLE_APPLICATION_CREDENTIALS"] = "path/to/service-account-key.json"

# Create Cloud Storage client
storage_client = storage.Client()

# Create Firestore client
firestore_client = firestore.Client()

# Create Pub/Sub client
pubsub_client = pubsub.PublisherClient()

def process_file(file_name):
    # Download file from Cloud Storage
    bucket = storage_client.bucket("your-bucket")
    blob = bucket.blob(file_name)
    data = blob.download_as_string()

    # Process file and write to Firestore
    doc_ref = firestore_client.collection("your-collection").document(file_name)
    doc_ref.set({"data": data})

    # Publish message to Pub/Sub
    topic = pubsub_client.topic("your-topic")
    message = {"filename": file_name, "data": data}
    topic.publish(message)

# Set up Cloud Storage trigger
storage_client.bucket("your-bucket").add_lifecycle_rule(
    lifecycle_action="process_file",
    condition={"age": 30},
    storage_class="NEARLINE"
)